import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface Meeting {
  title: string;
  time: string;
  location: string;
}

interface AgendaData {
  upcomingMeetings: Meeting[];
}

export default function Widget() {
  const agendaData = response.data.data as AgendaData;
  const { upcomingMeetings } = agendaData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#F5F5DC' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Typography variant="h6" fontWeight={600} sx={{ color: '#795548' }}>
            Upcoming Meetings
          </Typography>
          <Stack spacing={1.5}>
            {upcomingMeetings.map((meeting, index) => (
              <Box key={index}>
                <Typography variant="body2" fontWeight={500} sx={{ color: '#3E2723' }}>
                  {meeting.title}
                </Typography>
                <Stack direction="row" spacing={0.5}>
                  <Chip label={meeting.time} sx={{ fontSize: '10px', bgcolor: '#FFC107', color: '#000' }} />
                  <Chip label={meeting.location} sx={{ fontSize: '10px', bgcolor: '#00796B', color: '#FFF' }} />
                </Stack>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
